225	    quic_inspector: QuicLocatorInspector,
226	    #[cfg(feature = "transport_quic_datagram")]
227	    quic_datagram_inspector: QuicDatagramLocatorInspector,
228	    #[cfg(feature = "transport_tcp")]
229	    tcp_inspector: TcpLocatorInspector,
230	    #[cfg(feature = "transport_tls")]
231	    tls_inspector: TlsLocatorInspector,
232	    #[cfg(feature = "transport_udp")]
233	    udp_inspector: UdpLocatorInspector,
234	    #[cfg(feature = "transport_ws")]
235	    ws_inspector: WsLocatorInspector,
236	    #[cfg(all(feature = "transport_unixsock-stream", target_family = "unix"))]
237	    unixsock_stream_inspector: UnixSockStreamLocatorInspector,
238	    #[cfg(feature = "transport_serial")]
239	    serial_inspector: SerialLocatorInspector,
240	    #[cfg(feature = "transport_unixpipe")]
241	    unixpipe_inspector: UnixPipeLocatorInspector,
242	    #[cfg(all(feature = "transport_vsock", target_os = "linux"))]
243	    vsock_inspector: VsockLocatorInspector,
244	}
245	
246	impl fmt::Debug for LocatorInspector {
247	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
248	        f.debug_struct("LocatorInspector").finish_non_exhaustive()
249	    }
250	}
251	
252	impl LocatorInspector {
253	    pub fn is_reliable(&self, locator: &Locator) -> ZResult<bool> {
254	        #[allow(unused_imports)]
255	        use zenoh_link_commons::LocatorInspector;
256	        match LinkKind::try_from(locator)? {
257	            #[cfg(feature = "transport_tcp")]
258	            LinkKind::Tcp => self.tcp_inspector.is_reliable(locator),
259	            #[cfg(feature = "transport_udp")]
260	            LinkKind::Udp => self.udp_inspector.is_reliable(locator),
261	            #[cfg(feature = "transport_tls")]
262	            LinkKind::Tls => self.tls_inspector.is_reliable(locator),
263	            #[cfg(feature = "transport_quic")]
264	            LinkKind::Quic => self.quic_inspector.is_reliable(locator),
265	            #[cfg(feature = "transport_quic_datagram")]
266	            LinkKind::QuicDatagram => self.quic_datagram_inspector.is_reliable(locator),
267	            #[cfg(all(feature = "transport_unixsock-stream", target_family = "unix"))]
268	            LinkKind::UnixsockStream => self.unixsock_stream_inspector.is_reliable(locator),
269	            #[cfg(feature = "transport_ws")]
270	            LinkKind::Ws => self.ws_inspector.is_reliable(locator),
271	            #[cfg(feature = "transport_serial")]
272	            LinkKind::Serial => self.serial_inspector.is_reliable(locator),
273	            #[cfg(feature = "transport_unixpipe")]
274	            LinkKind::Unixpipe => self.unixpipe_inspector.is_reliable(locator),
275	            #[cfg(all(feature = "transport_vsock", target_os = "linux"))]
276	            LinkKind::Vscock => self.vsock_inspector.is_reliable(locator),
277	            #[allow(unreachable_patterns)]
278	            _ => unreachable!(),
279	        }
280	    }
281	
282	    pub async fn is_multicast(&self, locator: &Locator) -> ZResult<bool> {
283	        #[allow(unused_imports)]
284	        use zenoh_link_commons::LocatorInspector;
285	        match LinkKind::try_from(locator)? {
286	            #[cfg(feature = "transport_tcp")]
