14	use std::{cell::UnsafeCell, convert::TryInto, fmt, net::SocketAddr, sync::Arc, time::Duration};
15	
16	use async_trait::async_trait;
17	use tokio::{
18	    io::{AsyncReadExt, AsyncWriteExt},
19	    net::{TcpListener, TcpStream},
20	};
21	use tokio_util::sync::CancellationToken;
22	use zenoh_link_commons::{
23	    get_ip_interface_names, tcp::TcpSocketConfig, LinkAuthId, LinkManagerUnicastTrait, LinkUnicast,
24	    LinkUnicastTrait, ListenersUnicastIP, NewLinkChannelSender, BIND_INTERFACE, BIND_SOCKET,
25	};
26	use zenoh_protocol::{
27	    core::{EndPoint, Locator, Priority},
28	    transport::BatchSize,
29	};
30	use zenoh_result::{bail, zerror, Error as ZError, ZResult};
31	
32	use crate::{
33	    get_tcp_addrs, utils::TcpLinkConfig, TCP_ACCEPT_THROTTLE_TIME, TCP_DEFAULT_MTU,
34	    TCP_LINGER_TIMEOUT, TCP_LOCATOR_PREFIX,
35	};
36	
37	pub struct LinkUnicastTcp {
38	    // The underlying socket as returned from the tokio library
39	    socket: UnsafeCell<TcpStream>,
40	    // The source socket address of this link (address used on the local host)
41	    src_addr: SocketAddr,
42	    src_locator: Locator,
43	    // The destination socket address of this link (address used on the remote host)
44	    dst_addr: SocketAddr,
45	    dst_locator: Locator,
46	    // The computed mtu
47	    mtu: BatchSize,
48	}
49	
50	unsafe impl Sync for LinkUnicastTcp {}
51	
52	impl LinkUnicastTcp {
53	    fn new(socket: TcpStream, src_addr: SocketAddr, dst_addr: SocketAddr) -> LinkUnicastTcp {
54	        // Set the TCP nodelay option
55	        if let Err(err) = socket.set_nodelay(true) {
56	            tracing::warn!(
57	                "Unable to set NODEALY option on TCP link {} => {}: {}",
58	                src_addr,
59	                dst_addr,
60	                err
61	            );
62	        }
63	
64	        // Set the TCP linger option
65	        #[allow(deprecated)]
66	        if let Err(err) = socket.set_linger(Some(Duration::from_secs(
67	            (*TCP_LINGER_TIMEOUT).try_into().unwrap(),
68	        ))) {
69	            tracing::warn!(
70	                "Unable to set LINGER option on TCP link {} => {}: {}",
71	                src_addr,
72	                dst_addr,
73	                err
74	            );
75	        }
76	
77	        // Compute the MTU
78	        // See IETF RFC6691: https://datatracker.ietf.org/doc/rfc6691/
79	        let header = match src_addr.ip() {
80	            std::net::IpAddr::V4(_) => 40,
81	            std::net::IpAddr::V6(_) => 60,
82	        };
83	        #[allow(unused_mut)] // mut is not needed when target_family != unix
84	        let mut mtu = *TCP_DEFAULT_MTU - header;
85	
86	        // target limitation of socket2: https://docs.rs/socket2/latest/src/socket2/sys/unix.rs.html#1544
87	        #[cfg(target_family = "unix")]
88	        {
89	            let socket = socket2::SockRef::from(&socket);
90	            // Get the MSS and divide it by 2 to ensure we can at least fill half the MSS
91	            let mss = socket.mss().unwrap_or(mtu as u32) / 2;
92	            // Compute largest multiple of TCP MSS that is smaller of default MTU
93	            let mut tgt = mss;
94	            while (tgt + mss) < mtu as u32 {
95	                tgt += mss;
96	            }
97	            mtu = (mtu as u32).min(tgt) as BatchSize;
98	        }
99	
100	        // Build the Tcp object
101	        LinkUnicastTcp {
102	            socket: UnsafeCell::new(socket),
103	            src_addr,
104	            src_locator: Locator::new(TCP_LOCATOR_PREFIX, src_addr.to_string(), "").unwrap(),
105	            dst_addr,
106	            dst_locator: Locator::new(TCP_LOCATOR_PREFIX, dst_addr.to_string(), "").unwrap(),
107	            mtu,
108	        }
109	    }
110	
111	    #[allow(clippy::mut_from_ref)]
112	    fn get_mut_socket(&self) -> &mut TcpStream {
113	        unsafe { &mut *self.socket.get() }
114	    }
115	}
116	
117	#[async_trait]
118	impl LinkUnicastTrait for LinkUnicastTcp {
119	    async fn close(&self) -> ZResult<()> {
120	        tracing::trace!("Closing TCP link: {}", self);
121	        // Close the underlying TCP socket
122	        self.get_mut_socket().shutdown().await.map_err(|e| {
123	            let e = zerror!("TCP link shutdown {}: {:?}", self, e);
124	            tracing::trace!("{}", e);
125	            e.into()
126	        })
127	    }
128	
129	    async fn write(&self, buffer: &[u8], _priority: Option<Priority>) -> ZResult<usize> {
130	        self.get_mut_socket().write(buffer).await.map_err(|e| {
131	            let e = zerror!("Write error on TCP link {}: {}", self, e);
132	            tracing::trace!("{}", e);
133	            e.into()
134	        })
135	    }
136	
137	    async fn write_all(&self, buffer: &[u8], _priority: Option<Priority>) -> ZResult<()> {
138	        self.get_mut_socket().write_all(buffer).await.map_err(|e| {
139	            let e = zerror!("Write error on TCP link {}: {}", self, e);
140	            tracing::trace!("{}", e);
141	            e.into()
142	        })
143	    }
