385	async fn accept_task(
386	    socket: TcpListener,
387	    token: CancellationToken,
388	    manager: NewLinkChannelSender,
389	) -> ZResult<()> {
390	    async fn accept(socket: &TcpListener) -> ZResult<(TcpStream, SocketAddr)> {
391	        let res = socket.accept().await.map_err(|e| zerror!(e))?;
392	        Ok(res)
393	    }
394	
395	    let src_addr = socket.local_addr().map_err(|e| {
396	        let e = zerror!("Can not accept TCP connections: {}", e);
397	        tracing::warn!("{}", e);
398	        e
399	    })?;
400	
401	    tracing::trace!("Ready to accept TCP connections on: {:?}", src_addr);
402	    loop {
403	        tokio::select! {
404	            _ = token.cancelled() => break,
405	            res = accept(&socket) => {
406	                match res {
407	                    Ok((stream, dst_addr)) => {
408	                        // Get the right source address in case an unsepecified IP (i.e. 0.0.0.0 or [::]) is used
409	                        let src_addr =  match stream.local_addr()  {
410	                            Ok(sa) => sa,
411	                            Err(e) => {
412	                                tracing::debug!("Can not accept TCP connection: {}", e);
413	                                continue;
414	                            }
415	                        };
416	
417	                        tracing::debug!("Accepted TCP connection on {:?}: {:?}", src_addr, dst_addr);
418	                        // Create the new link object
419	                        let link: Arc<dyn LinkUnicastTrait> = Arc::new(LinkUnicastTcp::new(stream, src_addr, dst_addr));
420	
421	                        // Communicate the new link to the initial transport manager
422	                        if let Err(e) = manager.send_async(LinkUnicast::from(link)).await {
423	                            tracing::error!("{}-{}: {}", file!(), line!(), e)
424	                        }
425	                    },
426	                    Err(e) => {
427	                        tracing::warn!("{}. Hint: increase the system open file limit.", e);
428	                        // Throttle the accept loop upon an error
429	                        // NOTE: This might be due to various factors. However, the most common case is that
430	                        //       the process has reached the maximum number of open files in the system. On
431	                        //       Linux systems this limit can be changed by using the "ulimit" command line
432	                        //       tool. In case of systemd-based systems, this can be changed by using the
433	                        //       "sysctl" command line tool.
434	                        tokio::time::sleep(Duration::from_micros(*TCP_ACCEPT_THROTTLE_TIME)).await;
435	                    }
436	
437	                }
438	            }
439	        };
440	    }
