79	impl LinkUnicastUdpUnconnected {
80	    async fn received(&self, buffer: Vec<u8>, len: usize) {
81	        self.input.put((buffer, len)).await;
82	    }
83	
84	    async fn read(&self, buffer: &mut [u8]) -> ZResult<usize> {
85	        let mut guard = zasynclock!(self.leftover);
86	        let (slice, start, len) = match guard.take() {
87	            Some(tuple) => tuple,
88	            None => {
89	                let (slice, len) = self.input.take().await;
90	                (slice, 0, len)
91	            }
92	        };
93	        // Copy the read bytes into the target buffer
94	        let len_min = (len - start).min(buffer.len());
95	        let end = start + len_min;
96	        buffer[0..len_min].copy_from_slice(&slice[start..end]);
97	        if end < len {
98	            // Store the leftover
99	            *guard = Some((slice, end, len));
100	        } else {
101	            // Recycle the buffer
102	            drop(slice);
103	        }
104	        // Return the amount read
105	        Ok(len_min)
106	    }
107	
108	    async fn write(&self, buffer: &[u8], dst_addr: SocketAddr) -> ZResult<usize> {
109	        match self.socket.upgrade() {
110	            Some(socket) => socket
111	                .send_to(buffer, &dst_addr)
112	                .await
113	                .map_err(|e| zerror!(e).into()),
114	            None => bail!("UDP listener has been dropped"),
115	        }
116	    }
117	
118	    async fn close(&self, src_addr: SocketAddr, dst_addr: SocketAddr) -> ZResult<()> {
119	        // Delete the link from the list of links
120	        zlock!(self.links).remove(&(src_addr, dst_addr));
121	        Ok(())
122	    }
123	}
