183	    async fn write_all(&self, buffer: &[u8], priority: Option<Priority>) -> ZResult<()> {
184	        match &self.variant {
185	            LinkUnicastUdpVariant::Reliable(link) => link.write_all(buffer, priority).await,
186	            LinkUnicastUdpVariant::Connected(_) | LinkUnicastUdpVariant::Unconnected(_) => {
187	                let mut written: usize = 0;
188	                while written < buffer.len() {
189	                    written += self.write(&buffer[written..], priority).await?;
190	                }
191	                Ok(())
192	            }
193	        }
