207	            LinkUnicastUdpVariant::Connected(_) | LinkUnicastUdpVariant::Unconnected(_) => {
208	                let mut read: usize = 0;
209	                while read < buffer.len() {
210	                    let n = self.read(&mut buffer[read..], priority).await?;
211	                    read += n;
