320	    async fn new_link_inner(
321	        &self,
322	        dst_addr: &SocketAddr,
323	        iface: Option<&str>,
324	        bind_socket: Option<&str>,
325	        dscp: Option<u32>,
326	    ) -> ZResult<(UdpSocket, SocketAddr, SocketAddr)> {
327	        let src_socket_addr = if let Some(bind_socket) = bind_socket {
328	            let address = Address::from(bind_socket);
329	            get_udp_addrs(address)
330	                .await?
331	                .next()
332	                .ok_or_else(|| zerror!("No UDP socket addr found bound to {}", address))?
333	        } else if dst_addr.is_ipv4() {
334	            SocketAddr::new(Ipv4Addr::UNSPECIFIED.into(), 0)
335	        } else {
336	            SocketAddr::new(Ipv6Addr::UNSPECIFIED.into(), 0)
337	        };
338	
339	        // Establish a UDP socket
340	        let socket = UdpSocket::bind(src_socket_addr).await.map_err(|e| {
341	            let e = zerror!(
342	                "Can not create a new UDP link bound to {}: {}",
343	                src_socket_addr,
344	                e
345	            );
346	            tracing::warn!("{}", e);
347	            e
348	        })?;
349	
350	        if let Some(iface) = iface {
351	            zenoh_util::net::set_bind_to_device_udp_socket(&socket, iface)?;
352	        }
353	
354	        if let Some(dscp) = dscp {
355	            set_dscp(&socket, *dst_addr, dscp)?;
356	        }
357	
358	        // Connect the socket to the remote address
359	        socket.connect(dst_addr).await.map_err(|e| {
360	            let e = zerror!("Can not connect a new UDP link to {}: {}", dst_addr, e);
361	            tracing::warn!("{}", e);
362	            e
363	        })?;
364	
365	        // Get source and destination UDP addresses
366	        let src_addr = socket.local_addr().map_err(|e| {
367	            let e = zerror!(
368	                "Can not get local_addr for UDP link bound src {}: to :{} : {}",
369	                src_socket_addr,
370	                dst_addr,
371	                e
372	            );
373	            tracing::warn!("{}", e);
374	            e
375	        })?;
376	
377	        let dst_addr = socket.peer_addr().map_err(|e| {
378	            let e = zerror!(
379	                "Can not get peer_addr for UDP link bound src {}: to :{} : {}",
380	                src_socket_addr,
381	                dst_addr,
382	                e
383	            );
384	            tracing::warn!("{}", e);
385	            e
386	        })?;
387	
388	        Ok((socket, src_addr, dst_addr))
389	    }
