391	    async fn new_listener_inner(
392	        &self,
393	        addr: &SocketAddr,
394	        iface: Option<&str>,
395	        dscp: Option<u32>,
396	    ) -> ZResult<(UdpSocket, SocketAddr)> {
397	        // Bind the UDP socket
398	        let socket = UdpSocket::bind(addr).await.map_err(|e| {
399	            let e = zerror!("Can not create a new UDP listener on {}: {}", addr, e);
400	            tracing::warn!("{}", e);
401	            e
402	        })?;
403	
404	        if let Some(iface) = iface {
405	            zenoh_util::net::set_bind_to_device_udp_socket(&socket, iface)?;
406	        }
407	
408	        if let Some(dscp) = dscp {
409	            set_dscp(&socket, *addr, dscp)?;
410	        }
411	
412	        let local_addr = socket.local_addr().map_err(|e| {
413	            let e = zerror!("Can not create a new UDP listener on {}: {}", addr, e);
414	            tracing::warn!("{}", e);
415	            e
416	        })?;
417	
418	        Ok((socket, local_addr))
