421	    async fn new_udp_link(&self, endpoint: EndPoint) -> ZResult<LinkUnicast> {
422	        let dst_addrs = get_udp_addrs(endpoint.address())
423	            .await?
424	            .filter(|a| !a.ip().is_multicast());
425	        let config = endpoint.config();
426	        let iface = config.get(BIND_INTERFACE);
427	
428	        if let (Some(_), Some(_)) = (config.get(BIND_INTERFACE), config.get(BIND_SOCKET)) {
429	            bail!(
430	                "Using Config options `iface` and `bind` in conjunction is unsupported at this time {} {:?}",
431	                BIND_INTERFACE,
432	                BIND_SOCKET
433	            )
434	        }
435	
436	        let bind_socket = config.get(BIND_SOCKET);
437	        let dscp = parse_dscp(&config)?;
438	
439	        let mut errs: Vec<ZError> = vec![];
440	        for da in dst_addrs {
441	            match self.new_link_inner(&da, iface, bind_socket, dscp).await {
442	                Ok((socket, src_addr, dst_addr)) => {
443	                    // Create UDP link
444	                    let link = Arc::new(LinkUnicastUdp::new(
445	                        src_addr,
446	                        dst_addr,
447	                        LinkUnicastUdpVariant::Connected(LinkUnicastUdpConnected {
448	                            socket: Arc::new(socket),
449	                        }),
450	                    ));
451	
452	                    return Ok(LinkUnicast::from(link as Arc<dyn LinkUnicastTrait>));
453	                }
454	                Err(e) => {
455	                    errs.push(e);
456	                }
457	            }
458	        }
459	
460	        if errs.is_empty() {
461	            errs.push(zerror!("No UDP unicast addresses available").into());
462	        }
463	
464	        bail!(
465	            "Can not create a new UDP link bound to {}: {:?}",
466	            endpoint,
467	            errs
468	        )
469	    }
470	
471	    async fn new_udp_listener(&self, mut endpoint: EndPoint) -> ZResult<Locator> {
472	        let addrs = get_udp_addrs(endpoint.address())
473	            .await?
474	            .filter(|a| !a.ip().is_multicast());
475	        let config = endpoint.config();
476	        let iface = config.get(BIND_INTERFACE);
477	        let dscp = parse_dscp(&config)?;
478	
479	        let mut errs: Vec<ZError> = vec![];
480	        for da in addrs {
481	            match self.new_listener_inner(&da, iface, dscp).await {
482	                Ok((socket, local_addr)) => {
483	                    // Update the endpoint locator address
484	                    endpoint = EndPoint::new(
485	                        endpoint.protocol(),
486	                        local_addr.to_string(),
487	                        endpoint.metadata(),
488	                        endpoint.config(),
489	                    )?;
490	
491	                    let token = self.listeners.token.child_token();
492	
493	                    let task = {
494	                        let token = token.clone();
495	                        let manager = self.manager.clone();
496	
497	                        async move { accept_read_task(socket, token, manager).await }
498	                    };
499	
500	                    let locator = endpoint.to_locator();
501	                    self.listeners
502	                        .add_listener(endpoint, local_addr, task, token)
503	                        .await?;
504	
505	                    return Ok(locator);
506	                }
507	                Err(e) => {
508	                    errs.push(e);
509	                }
510	            }
511	        }
512	
513	        if errs.is_empty() {
514	            errs.push(zerror!("No UDP unicast addresses available").into());
515	        }
516	
517	        bail!(
518	            "Can not create a new UDP listener bound to {}: {:?}",
519	            endpoint,
520	            errs
521	        )
522	    }
523	}
