592	async fn accept_read_task(
593	    socket: UdpSocket,
594	    token: CancellationToken,
595	    manager: NewLinkChannelSender,
596	) -> ZResult<()> {
597	    let socket = Arc::new(socket);
598	    let links: LinkHashMap = Arc::new(Mutex::new(HashMap::new()));
599	
600	    macro_rules! zaddlink {
601	        ($src:expr, $dst:expr, $link:expr) => {
602	            zlock!(links).insert(($src, $dst), $link);
603	        };
604	    }
605	
606	    macro_rules! zdellink {
607	        ($src:expr, $dst:expr) => {
608	            zlock!(links).remove(&($src, $dst));
609	        };
610	    }
611	
612	    macro_rules! zgetlink {
613	        ($src:expr, $dst:expr) => {
614	            zlock!(links).get(&($src, $dst)).map(|link| link.clone())
615	        };
616	    }
617	
618	    async fn receive(
619	        socket: Arc<pktinfo::PktInfoUdpSocket>,
620	        buffer: &mut [u8],
621	    ) -> ZResult<(usize, SocketAddr, SocketAddr)> {
622	        let res = socket.receive(buffer).await.map_err(|e| zerror!(e))?;
623	        Ok(res)
624	    }
625	
626	    let local_src_addr = socket.local_addr().map_err(|e| {
627	        let e = zerror!("Can not accept UDP connections: {}", e);
628	        tracing::warn!("{}", e);
629	        e
630	    })?;
631	    let socket = Arc::new(pktinfo::PktInfoUdpSocket::new(socket).map_err(|e| {
632	        let e = zerror!("Failed to enable IP_PKTINFO: {}", e);
633	        tracing::warn!("{}", e);
634	        e
635	    })?);
636	
637	    tracing::trace!("Ready to accept UDP connections on: {:?}", local_src_addr);
638	
639	    loop {
640	        // Buffers for deserialization
641	        let mut buff = zenoh_buffers::vec::uninit(UDP_MAX_MTU as usize);
642	
643	        tokio::select! {
644	            _ = token.cancelled() => break,
645	
646	            res = receive(socket.clone(), &mut buff) => {
647	                match res {
648	                    Ok((n, dst_addr, src_addr)) => {
649	                        let link = loop {
650	                            let res = zgetlink!(src_addr, dst_addr);
651	                            match res {
652	                                Some(link) => break link.upgrade(),
653	                                None => {
654	                                    // A new peers has sent data to this socket
655	                                    tracing::debug!("Accepted UDP connection on {}: {}", src_addr, dst_addr);
656	                                    let unconnected = Arc::new(LinkUnicastUdpUnconnected {
657	                                        socket: Arc::downgrade(&socket.socket),
658	                                        links: links.clone(),
659	                                        input: Mvar::new(),
660	                                        leftover: AsyncMutex::new(None),
661	                                    });
662	                                    zaddlink!(src_addr, dst_addr, Arc::downgrade(&unconnected));
663	                                    // Create the new link object
664	                                    let link = Arc::new(LinkUnicastUdp::new(
665	                                        src_addr,
666	                                        dst_addr,
667	                                        LinkUnicastUdpVariant::Unconnected(unconnected),
668	                                    ));
669	                                    // Add the new link to the set of connected peers
670	                                    if let Err(e) = manager
671	                                        .send_async(LinkUnicast::from(link as Arc<dyn LinkUnicastTrait>))
672	                                        .await
673	                                    {
674	                                        tracing::error!("{}-{}: {}", file!(), line!(), e)
675	                                    }
676	                                }
677	                            }
678	                        };
679	
680	                        match link {
681	                            Some(link) => {
682	                                link.received(buff, n).await;
683	                            }
684	                            None => {
685	                                zdellink!(src_addr, dst_addr);
686	                            }
687	                        }
688	                    }
689	
690	                    Err(e) => {
691	                        tracing::warn!("{}. Hint: increase the system open file limit.", e);
692	                        // Throttle the accept loop upon an error
693	                        // NOTE: This might be due to various factors. However, the most common case is that
694	                        //       the process has reached the maximum number of open files in the system. On
695	                        //       Linux systems this limit can be changed by using the "ulimit" command line
696	                        //       tool. In case of systemd-based systems, this can be changed by using the
697	                        //       "sysctl" command line tool.
698	                        tokio::time::sleep(Duration::from_micros(*UDP_ACCEPT_THROTTLE_TIME)).await;
699	                    }
700	                }
701	            }
702	        }
703	    }
704	
705	    Ok(())
