69	#[async_trait]
70	impl LinkMulticastTrait for LinkMulticastUdp {
71	    async fn close(&self) -> ZResult<()> {
72	        tracing::trace!("Closing UDP link: {}", self);
73	        match self.multicast_addr.ip() {
74	            IpAddr::V4(dst_ip4) => match self.multicast_addr.ip() {
75	                IpAddr::V4(src_ip4) => self.mcast_sock.leave_multicast_v4(dst_ip4, src_ip4),
76	                IpAddr::V6(_) => unreachable!(),
77	            },
78	            IpAddr::V6(dst_ip6) => self.mcast_sock.leave_multicast_v6(&dst_ip6, 0),
79	        }
80	        .map_err(|e| {
81	            let e = zerror!("Close error on UDP link {}: {}", self, e);
82	            tracing::trace!("{}", e);
83	            e.into()
84	        })
85	    }
86	
87	    async fn write(&self, buffer: &[u8]) -> ZResult<usize> {
88	        match self
89	            .unicast_socket
90	            .send_to(buffer, self.multicast_addr)
91	            .await
92	        {
93	            Ok(size) => Ok(size),
94	            std::io::Result::Err(e) => {
95	                #[cfg(not(target_os = "macos"))]
96	                {
97	                    let e = zerror!("Write error on UDP link {}: {}", self, e);
98	                    tracing::trace!("{}", e);
99	                    Err(e.into())
100	                }
101	                #[cfg(target_os = "macos")]
102	                if let Some(55) = e.raw_os_error() {
103	                    // No buffer space available
104	                    tracing::trace!("Write error on UDP link {}: {}", self, e);
105	                    Ok(0)
106	                } else {
107	                    let e = zerror!("Write error on UDP link {}: {}", self, e);
108	                    tracing::trace!("{}", e);
109	                    Err(e.into())
110	                }
111	            }
112	        }
113	    }
114	
115	    async fn write_all(&self, buffer: &[u8]) -> ZResult<()> {
116	        let mut written: usize = 0;
117	        while written < buffer.len() {
118	            written += self.write(&buffer[written..]).await?;
119	        }
120	        Ok(())
121	    }
122	
123	    async fn read<'a>(&'a self, buffer: &mut [u8]) -> ZResult<(usize, Cow<'a, Locator>)> {
124	        loop {
125	            let (n, addr) = self.mcast_sock.recv_from(buffer).await.map_err(|e| {
126	                let e = zerror!("Read error on UDP link {}: {}", self, e);
127	                tracing::trace!("{}", e);
128	                e
129	            })?;
130	
131	            if self.unicast_addr == addr {
132	                continue; // We are reading our own messages, skip it
133	            } else {
134	                let locator = socket_addr_to_udp_locator(&addr);
135	                break Ok((n, Cow::Owned(locator)));
136	            }
137	        }
138	    }
