182	/*             MANAGER               */
183	/*************************************/
184	#[derive(Debug, Default)]
185	pub struct LinkManagerMulticastUdp;
186	
187	impl LinkManagerMulticastUdp {
188	    async fn new_link_inner(
189	        &self,
190	        mcast_addr: &SocketAddr,
191	        config: Config<'_>,
192	        bind_socket: Option<&str>,
193	        dscp: Option<u32>,
194	    ) -> ZResult<(UdpSocket, SocketAddr, UdpSocket, SocketAddr)> {
195	        let domain = match mcast_addr.ip() {
196	            IpAddr::V4(_) => Domain::IPV4,
197	            IpAddr::V6(_) => Domain::IPV6,
198	        };
199	
200	        // Get local unicast address to bind the socket on
201	        let mut local_addr = if let Some(bind_socket) = bind_socket {
202	            let bind_addr = SocketAddr::from_str(bind_socket)?;
203	            match (bind_addr, mcast_addr) {
204	                (SocketAddr::V6(local), SocketAddr::V4(dest)) => {
205	                    return Err(Box::from(format!(
206	                        "Protocols must match: Cannot bind to IPv6 {local} and join IPv4 {dest}"
207	                    )));
208	                }
209	                (SocketAddr::V4(local), SocketAddr::V6(dest)) => {
210	                    return Err(Box::from(format!(
211	                        "Protocols must match: Cannot bind to IPv4 {local} and join IPv6 {dest}"
212	                    )));
213	                }
214	                _ => bind_addr, // No issue here
215	            }
216	        } else if mcast_addr.is_ipv4() {
217	            SocketAddr::new(Ipv4Addr::UNSPECIFIED.into(), 0)
218	        } else {
219	            SocketAddr::new(Ipv6Addr::UNSPECIFIED.into(), 0)
220	        };
221	        if local_addr.ip() == IpAddr::V4(Ipv4Addr::UNSPECIFIED)
222	            || local_addr.ip() == IpAddr::V6(Ipv6Addr::UNSPECIFIED)
223	        {
224	            // Get default iface address to bind the socket on if provided
225	            let mut iface_addr: Option<IpAddr> = None;
226	            if let Some(iface) = config.get(UDP_MULTICAST_IFACE) {
227	                iface_addr = match iface.parse() {
228	                    Ok(addr) => Some(addr),
229	                    Err(_) => zenoh_util::net::get_unicast_addresses_of_interface(iface)?
230	                        .into_iter()
231	                        .filter(|x| match mcast_addr.ip() {
232	                            IpAddr::V4(_) => x.is_ipv4(),
233	                            IpAddr::V6(_) => x.is_ipv6(),
234	                        })
235	                        .take(1)
236	                        .collect::<Vec<IpAddr>>()
237	                        .first()
238	                        .copied(),
239	                };
240	            }
241	            if let Some(iface_addr) = iface_addr {
242	                local_addr.set_ip(iface_addr);
243	            } else if let Some(iface_addr) =
244	                zenoh_util::net::get_unicast_addresses_of_multicast_interfaces()
245	                    .into_iter()
246	                    .filter(|x| {
247	                        !x.is_loopback()
248	                            && match mcast_addr.ip() {
249	                                IpAddr::V4(_) => x.is_ipv4(),
250	                                IpAddr::V6(_) => x.is_ipv6(),
251	                            }
252	                    })
253	                    .take(1)
254	                    .collect::<Vec<IpAddr>>()
255	                    .first()
256	                    .copied()
257	            {
258	                local_addr.set_ip(iface_addr);
259	            }
260	        }
261	
262	        // Establish a unicast UDP socket
263	        let ucast_sock = Socket::new(domain, Type::DGRAM, Some(Protocol::UDP))
264	            .map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
265	        match &local_addr.ip() {
266	            IpAddr::V4(addr) => {
267	                ucast_sock
268	                    .set_multicast_if_v4(addr)
269	                    .map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
270	            }
271	            IpAddr::V6(_) => match zenoh_util::net::get_index_of_interface(local_addr.ip()) {
272	                Ok(idx) => ucast_sock
273	                    .set_multicast_if_v6(idx)
274	                    .map_err(|e| zerror!("{}: {}", mcast_addr, e))?,
275	                Err(e) => bail!("{}: {}", mcast_addr, e),
276	            },
277	        }
278	
279	        ucast_sock
280	            .bind(&local_addr.into())
281	            .map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
282	
283	        if let Some(dscp) = dscp {
284	            set_dscp(&ucast_sock, *mcast_addr, dscp)?;
285	        }
286	
287	        // Must set to nonblocking according to the doc of tokio
288	        // https://docs.rs/tokio/latest/tokio/net/struct.UdpSocket.html#notes
289	        ucast_sock.set_nonblocking(true)?;
290	        let ucast_sock = UdpSocket::from_std(ucast_sock.into())?;
291	
292	        // Establish a multicast UDP socket
293	        let mcast_sock = Socket::new(domain, Type::DGRAM, Some(Protocol::UDP))
294	            .map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
295	        mcast_sock
296	            .set_reuse_address(true)
297	            .map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
298	        #[cfg(target_family = "unix")]
299	        {
300	            mcast_sock
301	                .set_reuse_port(true)
302	                .map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
303	        }
304	
305	        // Bind the socket: let's bind to the unspecified address so we can join and read
306	        // from multiple multicast groups.
307	        let bind_mcast_addr = match mcast_addr.ip() {
308	            IpAddr::V4(_) => IpAddr::V4(Ipv4Addr::UNSPECIFIED),
309	            IpAddr::V6(_) => IpAddr::V6(Ipv6Addr::UNSPECIFIED),
310	        };
311	        mcast_sock
312	            .bind(&SocketAddr::new(bind_mcast_addr, mcast_addr.port()).into())
313	            .map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
314	
315	        // Join the multicast group
316	        let join = config.values(UDP_MULTICAST_JOIN);
317	        match mcast_addr.ip() {
318	            IpAddr::V4(dst_ip4) => match local_addr.ip() {
319	                IpAddr::V4(src_ip4) => {
320	                    // Join default multicast group
321	                    mcast_sock
322	                        .join_multicast_v4(&dst_ip4, &src_ip4)
323	                        .map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
324	                    // Join any additional multicast group
325	                    for g in join {
326	                        let g: Ipv4Addr =
327	                            g.parse().map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
328	                        mcast_sock
329	                            .join_multicast_v4(&g, &src_ip4)
330	                            .map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
331	                    }
332	                }
333	                IpAddr::V6(src_ip6) => bail!("{}: unexpected IPv6 source address", src_ip6),
334	            },
335	            IpAddr::V6(dst_ip6) => {
336	                // Join default multicast group
337	                mcast_sock
338	                    .join_multicast_v6(&dst_ip6, 0)
339	                    .map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
340	                // Join any additional multicast group
341	                for g in join {
342	                    let g: Ipv6Addr = g.parse().map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
343	                    mcast_sock
344	                        .join_multicast_v6(&g, 0)
345	                        .map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
346	                }
347	            }
348	        };
349	
350	        // Must set to nonblocking according to the doc of tokio
351	        // https://docs.rs/tokio/latest/tokio/net/struct.UdpSocket.html#notes
352	        mcast_sock.set_nonblocking(true)?;
353	
354	        // If TTL is specified, add set the socket's TTL
355	        if let Some(ttl_str) = config.get(UDP_MULTICAST_TTL) {
356	            match &local_addr.ip() {
357	                IpAddr::V4(_) => {
358	                    let ttl = match ttl_str.parse::<u32>() {
359	                        Ok(ttl) => ttl,
360	                        Err(e) => bail!("Can not parse TTL '{}' to a u32: {}", ttl_str, e),
361	                    };
362	
363	                    ucast_sock.set_multicast_ttl_v4(ttl).map_err(|e| {
364	                        zerror!("Can not set multicast TTL {} on {}: {}", ttl, mcast_addr, e)
365	                    })?;
366	                }
367	                IpAddr::V6(_) => {
368	                    tracing::warn!(
369	                            "UDP multicast hop limit not supported for v6 socket: {}. See https://github.com/rust-lang/rust/pull/138744.",
370	                            mcast_addr
371	                        );
372	                }
373	            }
374	        }
375	
376	        // Build the tokio multicast UdpSocket
377	        let mcast_sock = UdpSocket::from_std(mcast_sock.into())?;
378	
379	        let ucast_addr = ucast_sock
380	            .local_addr()
381	            .map_err(|e| zerror!("{}: {}", mcast_addr, e))?;
382	        assert_eq!(ucast_addr.ip(), local_addr.ip());
383	        // We may have bind to port 0, so we need to retrieve the actual port
384	        let mcast_port = mcast_sock
385	            .local_addr()
386	            .map_err(|e| zerror!("{}: {}", mcast_addr, e))?
387	            .port();
388	        let mcast_addr = SocketAddr::new(mcast_addr.ip(), mcast_port);
389	
390	        Ok((mcast_sock, mcast_addr, ucast_sock, ucast_addr))
391	    }
392	}
393	
394	#[async_trait]
395	impl LinkManagerMulticastTrait for LinkManagerMulticastUdp {
396	    async fn new_link(&self, endpoint: &EndPoint) -> ZResult<LinkMulticast> {
397	        let mcast_addrs = get_udp_addrs(endpoint.address())
398	            .await?
399	            .filter(|a| a.ip().is_multicast())
400	            .collect::<Vec<SocketAddr>>();
401	        let config = endpoint.config();
402	        let bind_socket = config.get(BIND_SOCKET);
403	        let dscp = parse_dscp(&config)?;
404	
405	        let mut errs: Vec<ZError> = vec![];
406	        for maddr in mcast_addrs {
407	            match self
408	                .new_link_inner(&maddr, endpoint.config(), bind_socket, dscp)
409	                .await
410	            {
411	                Ok((mcast_sock, mcast_addr, ucast_sock, ucast_addr)) => {
412	                    let link = Arc::new(LinkMulticastUdp::new(
413	                        ucast_addr, ucast_sock, mcast_addr, mcast_sock,
414	                    ));
415	
416	                    return Ok(LinkMulticast(link));
417	                }
418	                Err(e) => {
419	                    errs.push(e);
420	                }
421	            }
422	        }
423	
424	        if errs.is_empty() {
425	            errs.push(zerror!("No UDP multicast addresses available").into());
426	        }
427	
428	        bail!(
429	            "Can not create a new UDP link bound to {}: {:?}",
430	            endpoint,
431	            errs
432	        )
433	    }
434	}
